#include <bits/stdc++.h>
using namespace std;

int solve(int idx,int i,int j,int k,int dist,int turns){
 if(idx == turns && i == j && j== k){
  return 1;
 }

 if(j>i || k>j){
  return 0;
 }

 if( (i-j) > dist || (j-k) > dist ){
  return 0;
 }

 if(idx == turns && (i !=j || j!= k)){
  return 0;
 }

 int first = 0;
 int second= 0;
 int third = 0;

 for(int z = 1;z<=dist;z++){
  first += solve(idx+1,i+z,j,k,dist,turns);
  second += solve(idx+1,i,j+z,k,dist,turns);
  third += solve(idx+1,i,j,k+z,dist,turns);
 }

 return (first+second+third);

}

int main() {
 int d,k;
 cin >> d >> k;

 int answ = solve(0,0,0,0,d,k);
 cout << answ;
 return 0;
}

