vector<int> scheduleTasks(vector<int>& taskDeadlines, vector<int>& taskRewards) {

 int n = taskDeadlines.size();
 priority_queue< pair<int,int> > pq;
 for(int i=0;i<n;i++){
  pq.push({taskRewards[i],taskDeadlines[i]});
 }

 int maxdead = 0;
 for(int i=0;i<n;i++){
  maxdead = max(maxdead,taskDeadlines[i]);
 }

 maxdead = maxdead+1;

 vector<int> slot(maxdead,0);
 slot[0] = 1;

 int count = 0;
 int profit = 0;

 while(!pq.empty()){
  auto top = pq.top();
  pq.pop();

  int start = top.second;
  int p = top.first;

  for(int i=start;i>=0;i--){
   if(slot[i] == 0){
    slot[i] = 1;
    count++;
    profit = profit + p;
    break;
   }
  }
 }
 return {count,profit};
}

