#include <iostream>
using namespace std;

vector<int> scheduleTasks(vector<int>& taskDeadlines, vector<int>& taskRewards) {

 vector <int> ans;
 vector<pair><int,int> task; 

 for(int i = 0; i<taskDeadlines.size(){
  task.push_back(taskRewards[i], taskDeadlines[i]);
 }


 vector <int> timeslots;
 sort(taskRewards.begin(), taskRewards.end());

 int maxdead= 0; 

 for (int i = 0; i< taskDeadlines.size(); i++){
  maxdead = max(maxdead, taskDeadlines[i]);

 }

 vector <int> slots(maxdead + 1, -1);

 int sum1 = 0; int sum2 = 0;
 for(int i = 0; i< taskDeadlines.size(); i++){
  if(slots[task[i].second == 1]);
  sum1 += 1;
  sum2 += task.first;
  slots[task[i].second] = 1;
 }

 ans.push_push_back(sum1);
 ans.push_back(sum2);

}


int main(){

 int n;
 cout<<"enter number of tasks"<<endl;
 cin>>n;

 vector <int> taskDeadlines[n];
 vector <int> taskRewards[n];

 cout<<"enter deadline and reward for tasks"<<endl;
 for(int i = 0; i<n; i++){
  cin>>taskDeadlines[i];
  cin>>taskRewards[i]
 }


}
